import{_ as a,o as e,c as r,a2 as o}from"./chunks/framework.Crpw6aS5.js";const _=JSON.parse('{"title":"BNSF铁路","description":"","frontmatter":{"title":"BNSF铁路"},"headers":[],"relativePath":"03_companies/BNSF铁路.md","filePath":"03_companies/BNSF铁路.md"}'),n={name:"03_companies/BNSF铁路.md"};function d(i,t,l,s,h,c){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="bnsf铁路" tabindex="-1">BNSF铁路 <a class="header-anchor" href="#bnsf铁路" aria-label="Permalink to &quot;BNSF铁路&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><ul><li><strong>首次提及</strong>: 2009年</li><li><strong>持股情况</strong>: 2009年完成收购（2010年2月12日完成），约340亿美元，伯克希尔100%持有</li><li><strong>行业</strong>: 铁路运输</li><li><strong>英文名</strong>: BNSF Railway (Burlington Northern Santa Fe)</li></ul><h2 id="巴菲特论述" tabindex="-1">巴菲特论述 <a class="header-anchor" href="#巴菲特论述" aria-label="Permalink to &quot;巴菲特论述&quot;">​</a></h2><p>这是伯克希尔的&quot;四大珍宝&quot;之一，按货运量计是美国最大的铁路公司。</p><p>2010年2月12日完成收购，增加了约65,000名股东，使伯克希尔股东总数达到约50万人。BNSF覆盖北美的六大铁路系统中最大的一个，运输美国境内约15%的非本地吨英里货物。</p><p>固定资产700亿美元记录了23,759英里主线、99条隧道、13,495座桥梁、7,521台机车。自收购以来投资410亿美元固定资产，支付股息418亿美元。复制这些资产至少需要5000亿美元，且需要数十年——这是巴菲特眼中&quot;护城河&quot;的完美例证。</p><h2 id="收益变化" tabindex="-1">收益变化 <a class="header-anchor" href="#收益变化" aria-label="Permalink to &quot;收益变化&quot;">​</a></h2><table tabindex="0"><thead><tr><th>年份</th><th>收益</th></tr></thead><tbody><tr><td>2021年</td><td>60亿美元</td></tr><tr><td>2022年</td><td>59亿美元</td></tr><tr><td>2023年</td><td>50.87亿美元</td></tr><tr><td>2024年</td><td>50.31亿美元</td></tr></tbody></table><h2 id="投资要点" tabindex="-1">投资要点 <a class="header-anchor" href="#投资要点" aria-label="Permalink to &quot;投资要点&quot;">​</a></h2><p>巴菲特认为铁路是运输大宗货物的最高效方式，BNSF拥有无可复制的资产基础。这是典型的&quot;重资产、高护城河&quot;投资，虽然需要大量资本支出，但拥有持久的竞争优势。</p><h2 id="关联年份" tabindex="-1">关联年份 <a class="header-anchor" href="#关联年份" aria-label="Permalink to &quot;关联年份&quot;">​</a></h2><p>1850, 2009, 2010, 2020, 2021, 2022, 2023, 2024</p>',13)])])}const p=a(n,[["render",d]]);export{_ as __pageData,p as default};
